// Mirrors assets/js/lib/core.js's shouldSkipVerification. Keep the two in sync.
// Update this holiday list to match the current year's NSE trading calendar.
const NSE_HOLIDAYS_2026 = ['2026-01-26', '2026-03-14', '2026-08-15', '2026-10-02', '2026-11-14', '2026-12-25'];

function shouldSkipVerification(date, holidayList = []) {
  const d = new Date(date + 'T00:00:00Z');
  const dow = d.getUTCDay();
  if (dow === 0 || dow === 6) return { skip: true, reason: 'weekend' };
  if (holidayList.includes(date)) return { skip: true, reason: 'holiday' };
  return { skip: false, reason: null };
}

const today = new Date().toISOString().slice(0, 10);
const gate = shouldSkipVerification(today, NSE_HOLIDAYS_2026);
return [{ json: { skip: gate.skip, reason: gate.reason, today } }];

// --- resilient GitHub-helper accessors (n8n sandbox quirks; see below) ---
// httpRequest: $helpers.httpRequest can be undefined/unbound on some n8n builds
// (a long-standing sandbox bug). this.helpers.httpRequest is the reliable form,
// so prefer it and only fall back to $helpers.httpRequest.
const httpRequest = (this && this.helpers && this.helpers.httpRequest)
  ? this.helpers.httpRequest.bind(this.helpers)
  : $helpers.httpRequest;
// Token: $env is the reliable accessor for env vars inside the Code/Function
// sandbox; process.env is blocked (returns undefined) on n8n Cloud and when
// N8N_BLOCK_ENV_ACCESS_IN_NODE is set. Read via $env, fall back to process.env.
const GITHUB_TOKEN = (typeof $env !== 'undefined' && $env.GITHUB_TOKEN)
  ? $env.GITHUB_TOKEN
  : process.env.GITHUB_TOKEN;

// Fetch data/index.json and pick the latest date strictly before today.
const { today } = items[0].json;

// NOTE: never let a raw error from $helpers.httpRequest (or any library call)
// escape this function uncaught. n8n's legacy Function node has a bug in its own
// error formatter (Function.node.ts) that crashes with "Cannot read properties
// of undefined (reading 'split')" whenever the real error's stack trace doesn't
// contain the literal word "Function" — which hides the actual failure. Always
// catch and re-throw a fresh `new Error(...)` built right here instead, so a
// normal, readable message and stack always reach n8n's execution log.
function asObject(res) { return typeof res === 'string' ? JSON.parse(res) : res; }

let indexRes;
try {
  const raw = await httpRequest({
    method: 'GET',
    url: 'https://api.github.com/repos/bmdeshmukh18/briefing/contents/data/index.json',
    headers: {
      'Authorization': `Bearer ${GITHUB_TOKEN}`,
      'Accept': 'application/vnd.github.v3+json'
    },
    json: true
  });
  indexRes = asObject(raw);
} catch (e) {
  throw new Error(`GitHub GET failed for data/index.json: ${e?.message || e}`);
}
const dates = JSON.parse(Buffer.from(indexRes.content, 'base64').toString()).dates || [];
const priorDate = [...dates].filter(d => d < today).sort().at(-1);

if (!priorDate) {
  throw new Error(`No prior trading day found in index.json before ${today}`);
}

return [{ json: { priorDate } }];

// --- resilient GitHub-helper accessors (n8n sandbox quirks; see below) ---
// httpRequest: $helpers.httpRequest can be undefined/unbound on some n8n builds
// (a long-standing sandbox bug). this.helpers.httpRequest is the reliable form,
// so prefer it and only fall back to $helpers.httpRequest.
const httpRequest = (this && this.helpers && this.helpers.httpRequest)
  ? this.helpers.httpRequest.bind(this.helpers)
  : $helpers.httpRequest;
// Token: $env is the reliable accessor for env vars inside the Code/Function
// sandbox; process.env is blocked (returns undefined) on n8n Cloud and when
// N8N_BLOCK_ENV_ACCESS_IN_NODE is set. Read via $env, fall back to process.env.
const GITHUB_TOKEN = (typeof $env !== 'undefined' && $env.GITHUB_TOKEN)
  ? $env.GITHUB_TOKEN
  : process.env.GITHUB_TOKEN;

// Fetch and decode the prior day's Briefing_File.
const { priorDate } = items[0].json;
const path = `data/briefings/${priorDate}.json`;

// NOTE: never let a raw error from $helpers.httpRequest (or any library call)
// escape this function uncaught. n8n's legacy Function node has a bug in its own
// error formatter (Function.node.ts) that crashes with "Cannot read properties
// of undefined (reading 'split')" whenever the real error's stack trace doesn't
// contain the literal word "Function" — which hides the actual failure. Always
// catch and re-throw a fresh `new Error(...)` built right here instead, so a
// normal, readable message and stack always reach n8n's execution log.
function asObject(res) { return typeof res === 'string' ? JSON.parse(res) : res; }

let res;
try {
  const raw = await httpRequest({
    method: 'GET',
    url: `https://api.github.com/repos/bmdeshmukh18/briefing/contents/${path}`,
    headers: {
      'Authorization': `Bearer ${GITHUB_TOKEN}`,
      'Accept': 'application/vnd.github.v3+json'
    },
    json: true
  });
  res = asObject(raw);
} catch (e) {
  throw new Error(`GitHub GET failed for ${path}: ${e?.message || e}`);
}
const briefing = JSON.parse(Buffer.from(res.content, 'base64').toString());

return [{ json: { briefing, priorDate, path } }];

// --- resilient GitHub-helper accessors (n8n sandbox quirks; see below) ---
// httpRequest: $helpers.httpRequest can be undefined/unbound on some n8n builds
// (a long-standing sandbox bug). this.helpers.httpRequest is the reliable form,
// so prefer it and only fall back to $helpers.httpRequest.
const httpRequest = (this && this.helpers && this.helpers.httpRequest)
  ? this.helpers.httpRequest.bind(this.helpers)
  : $helpers.httpRequest;

// Yahoo Finance primary (30s timeout), Upstox backup (30s timeout) on failure.
// Both failing leaves prediction_result untouched (R7.9) — no partial write.
const { briefing, priorDate, path } = items[0].json;

function asObject(res) { return typeof res === 'string' ? JSON.parse(res) : res; }

async function fetchYahoo() {
  const raw = await httpRequest({
    method: 'GET',
    url: 'https://query1.finance.yahoo.com/v8/finance/chart/%5ENSEI?interval=1d&range=2d',
    json: true,
    timeout: 30000
  });
  const res = asObject(raw);
  const close = res?.chart?.result?.[0]?.meta?.regularMarketPrice;
  if (typeof close !== 'number') throw new Error('Yahoo Finance: no close price in response');
  return close;
}

async function fetchUpstox() {
  // Requires an UPSTOX_TOKEN credential/env var provisioned by the user.
  const raw = await httpRequest({
    method: 'GET',
    url: 'https://api.upstox.com/v2/market-quote/ltp?symbol=NSE_INDEX%7CNifty%2050',
    headers: { 'Authorization': `Bearer ${process.env.UPSTOX_TOKEN}` },
    json: true,
    timeout: 30000
  });
  const res = asObject(raw);
  const key = Object.keys(res?.data || {})[0];
  const close = res?.data?.[key]?.last_price;
  if (typeof close !== 'number') throw new Error('Upstox: no close price in response');
  return close;
}

let actualClose;
try {
  actualClose = await fetchYahoo();
} catch (yahooErr) {
  try {
    actualClose = await fetchUpstox();
  } catch (upstoxErr) {
    return [{ json: { bothFailed: true, priorDate, message: `Yahoo: ${yahooErr.message}; Upstox: ${upstoxErr.message}` } }];
  }
}

return [{ json: { bothFailed: false, actualClose, briefing, priorDate, path } }];

// Mirrors assets/js/lib/core.js's classifyAccuracy. Keep the two in sync.
function classifyAccuracy(actualClose, scenarios) {
  if (!Array.isArray(scenarios) || scenarios.length === 0) {
    return { accuracy_tag: 'Wrong', matched_scenario: null };
  }
  const inRange = s => actualClose >= s.range_low && actualClose <= s.range_high;
  const top = scenarios.reduce((best, s) => s.probability > best.probability ? s : best, scenarios[0]);
  if (inRange(top)) return { accuracy_tag: 'Correct', matched_scenario: top.name };
  const matching = scenarios.filter(inRange);
  if (matching.length > 0) {
    const best = matching.reduce((b, s) => s.probability > b.probability ? s : b, matching[0]);
    return { accuracy_tag: 'Partial', matched_scenario: best.name };
  }
  return { accuracy_tag: 'Wrong', matched_scenario: null };
}

const { actualClose, briefing, priorDate, path } = items[0].json;
const scenarios = briefing.outlook?.scenarios || [];
const { accuracy_tag, matched_scenario } = classifyAccuracy(actualClose, scenarios);

// Change vs. the prior day's own close (consistent with how nifty50.change_pct
// is computed elsewhere) — confirm this matches intent before relying on it.
const priorClose = briefing.summary?.nifty50?.close ?? null;
const actual_change_pct = priorClose ? Math.round(((actualClose - priorClose) / priorClose) * 10000) / 100 : null;

const prediction_result = {
  actual_close: actualClose,
  actual_change_pct,
  matched_scenario,
  accuracy_tag,
  verified_at: new Date().toISOString(),
};

return [{ json: { briefing, priorDate, path, prediction_result } }];

// --- resilient GitHub-helper accessors (n8n sandbox quirks; see below) ---
// httpRequest: $helpers.httpRequest can be undefined/unbound on some n8n builds
// (a long-standing sandbox bug). this.helpers.httpRequest is the reliable form,
// so prefer it and only fall back to $helpers.httpRequest.
const httpRequest = (this && this.helpers && this.helpers.httpRequest)
  ? this.helpers.httpRequest.bind(this.helpers)
  : $helpers.httpRequest;
// Token: $env is the reliable accessor for env vars inside the Code/Function
// sandbox; process.env is blocked (returns undefined) on n8n Cloud and when
// N8N_BLOCK_ENV_ACCESS_IN_NODE is set. Read via $env, fall back to process.env.
const GITHUB_TOKEN = (typeof $env !== 'undefined' && $env.GITHUB_TOKEN)
  ? $env.GITHUB_TOKEN
  : process.env.GITHUB_TOKEN;

// Re-fetch current sha (may have changed since the initial read) and merge
// prediction_result into the untouched rest of the file.
const { briefing, priorDate, path, prediction_result } = items[0].json;

// NOTE: never let a raw error from $helpers.httpRequest (or any library call)
// escape this function uncaught. n8n's legacy Function node has a bug in its own
// error formatter (Function.node.ts) that crashes with "Cannot read properties
// of undefined (reading 'split')" whenever the real error's stack trace doesn't
// contain the literal word "Function" — which hides the actual failure. Always
// catch and re-throw a fresh `new Error(...)` built right here instead, so a
// normal, readable message and stack always reach n8n's execution log.
function asObject(res) { return typeof res === 'string' ? JSON.parse(res) : res; }

let current;
try {
  const rawCurrent = await httpRequest({
    method: 'GET',
    url: `https://api.github.com/repos/bmdeshmukh18/briefing/contents/${path}`,
    headers: {
      'Authorization': `Bearer ${GITHUB_TOKEN}`,
      'Accept': 'application/vnd.github.v3+json'
    },
    json: true
  });
  current = asObject(rawCurrent);
} catch (e) {
  throw new Error(`GitHub GET failed for ${path}: ${e?.message || e}`);
}
const currentBriefing = JSON.parse(Buffer.from(current.content, 'base64').toString());
const updated = { ...currentBriefing, prediction_result };
const newContent = Buffer.from(JSON.stringify(updated, null, 2)).toString('base64');

try {
  await httpRequest({
    method: 'PUT',
    url: `https://api.github.com/repos/bmdeshmukh18/briefing/contents/${path}`,
    headers: {
      'Authorization': `Bearer ${GITHUB_TOKEN}`,
      'Content-Type': 'application/json',
      'Accept': 'application/vnd.github.v3+json'
    },
    body: JSON.stringify({
      message: `Verify prediction for ${priorDate}`,
      content: newContent,
      branch: 'main',
      sha: current.sha
    })
  });
} catch (e) {
  throw new Error(`GitHub PUT failed for ${path}: ${e?.message || e}`);
}

return [{ json: { success: true, priorDate, prediction_result } }];

